export const INSTANCE_STRIDE_BYTES = 12
export const INSTANCE_STRIDE_F32 = 3

export const FIELD_OFFSET_F32 = {
  startOff: 0,
  endOff: 1,
  y: 2,
} as const

export const GL_ATTRIBUTES: readonly GlAttributeLayout[] = [
  { name: 'a_startOff', components: 1, type: 'uint', offsetBytes: 0, integer: true },
  { name: 'a_endOff', components: 1, type: 'uint', offsetBytes: 4, integer: true },
  { name: 'a_y', components: 1, type: 'float', offsetBytes: 8, integer: false },
]

export interface InstanceArrays {
  startOff: ArrayLike<number>
  endOff: ArrayLike<number>
  y: ArrayLike<number>
}

export function packInstances(
  arrays: InstanceArrays,
  numInstances: number,
  buf: ArrayBuffer = new ArrayBuffer(numInstances * INSTANCE_STRIDE_BYTES),
) {
  const f32 = new Float32Array(buf)
  const u32 = new Uint32Array(buf)
  const { startOff, endOff, y } = arrays
  for (let i = 0; i < numInstances; i++) {
    const o = i * INSTANCE_STRIDE_F32
    u32[o + 0] = startOff[i]!
    u32[o + 1] = endOff[i]!
    f32[o + 2] = y[i]!
  }
  return buf
}
